return (async () => {
  const webhookNode = $("MCP Code Payload").first();
  const meta = webhookNode.json?.body || webhookNode.json || {};

  if (meta.commits || meta.pusher || meta.probe) return [];

  const stateNode = $("Fetch Main State").first();
  let stateRaw = null;
  if (stateNode.json && typeof stateNode.json.content === 'string') { stateRaw = stateNode.json.content; }
  if (!stateRaw && stateNode.binary && stateNode.binary.data) {
    const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');
    stateRaw = buffer.toString('utf8');
  }
  if (!stateRaw || stateRaw === "undefined") throw new Error("FATAL: state.json content is missing.");
  let state;
  try { state = JSON.parse(stateRaw); } catch (e) { state = JSON.parse(Buffer.from(stateRaw, 'base64').toString('utf8')); }
  let updatedState = { ...state };
  updatedState.current_phase = (meta.incoming_phase || state.current_phase || "43.1.35").toString();
  return [{ json: { updated_state: updatedState, meta: meta } }];
})();

const stateManager = $("State Manager").first().json;
const systemStatusData = $("Fetch System Status").first().json || {};
let currentStatus = "GREEN";
if (systemStatusData.documents && Array.isArray(systemStatusData.documents)) {
  const currentDoc = systemStatusData.documents.find(doc => doc.name.endsWith('telemetry/current'));
  if (currentDoc && currentDoc.fields && currentDoc.fields.status) {
    currentStatus = currentDoc.fields.status.stringValue || "GREEN";
  }
}
const summary = stateManager.meta?.summary || "";
const isBugFix = summary.toLowerCase().startsWith("fix") || summary.toLowerCase().startsWith("hotfix") || summary.toLowerCase().includes("fix(");
const intent = isBugFix ? "BUG_FIX" : "FUNCTIONALITY";
let throttleDecision = "PROCEED";
let throttleMessage = "Proceeding with deployment.";
if (currentStatus === "RED") {
  if (intent === "FUNCTIONALITY") {
    throttleDecision = "BLOCKED";
    throttleMessage = "System is in RED state (Fatal Errors). Feature deployments are BLOCKED. Only Bug Fixes are permitted.";
  } else {
    throttleMessage = "System is in RED state. Bug Fix prioritized and proceeding.";
  }
} else if (currentStatus === "YELLOW") {
  if (intent === "FUNCTIONALITY") {
    throttleDecision = "DELAYED";
    throttleMessage = "System is in YELLOW state (Elevated Warnings). Feature deployment throttled (delayed by 60 seconds).";
  } else {
    throttleMessage = "System is in YELLOW state. Bug Fix proceeding normally.";
  }
}
return [{ json: { ...stateManager, throttle_decision: throttleDecision, throttle_message: throttleMessage, system_status: currentStatus, intent: intent } }];

return (async () => {
  const stateNode = $("Fetch Latest State").first();
  let stateRaw = stateNode.json?.content || null;
  if (stateRaw) {
    stateRaw = Buffer.from(stateRaw, 'base64').toString('utf8');
  }
  if (!stateRaw || stateRaw === "undefined") throw new Error("FATAL: state.json content is missing or undefined.");
  let state;
  try { state = JSON.parse(stateRaw); } catch (e) { state = JSON.parse(Buffer.from(stateRaw, 'base64').toString('utf8')); }
  const action = $("Approval Listener").first().json.query.action;
  const approvedPhase = $("Approval Listener").first().json.query.phase;
  const rawHbrId = $("Approval Listener").first().json.query.hbrId;
  const buildId = $("Approval Listener").first().json.query.build_id;
  let filePath = ""; let fileContent = ""; let extractedReason = "";
  try {
    const resp = $("Fetch Proposal Data").first().json;
    let firestoreData = {};
    if (Array.isArray(resp) && resp.length > 0 && resp[0].document) firestoreData = resp[0].document;
    else if (resp && resp.document) firestoreData = resp.document;
    else if (resp && resp.fields) firestoreData = resp;
    const payloadFields = firestoreData.fields?.payload?.mapValue?.fields?.manifest?.mapValue?.fields || {};
    if (payloadFields.targetPath?.stringValue) filePath = payloadFields.targetPath.stringValue;
    if (payloadFields.proposedLogic?.stringValue) fileContent = payloadFields.proposedLogic.stringValue;
    if (payloadFields.reason?.stringValue) extractedReason = payloadFields.reason.stringValue;
  } catch (e) { console.log("Missing payload file data"); }
  let originalMeta = {};
  try { originalMeta = $("State Manager").first().json.meta || {}; } catch (e) {}
  let updatedState = { ...state }; 
  if (approvedPhase) { updatedState.current_phase = approvedPhase; }
  const logResponse = $("Log Scraper").first().json || {}; 
  let auditPassed = (logResponse.entries || []).length === 0 && action !== 'decline';
  let notificationText = action === 'decline' ? "🛑 Phase " + updatedState.current_phase + " DECLINED." : (auditPassed ? "✅ Phase " + updatedState.current_phase + " PROMOTED from " + state.current_phase + "." : "❌ Phase " + updatedState.current_phase + " FAILED AUDIT.");
  if (auditPassed) {
    updatedState.approval_gate = updatedState.approval_gate || {};
    updatedState.approval_gate.pending = false;
    updatedState.approval_gate.status = "PROMOTED";
  }
  const isProposal = !!rawHbrId && !['', 'undefined', 'null'].includes(rawHbrId);

  let finalFilePath = originalMeta.filePath || filePath;

  if (!finalFilePath || finalFilePath === 'null' || finalFilePath.includes('does_not_exist')) { 
    finalFilePath = 'IGNORE'; 
  } else { 
    finalFilePath = finalFilePath.trim().replace(/^\/+/, ''); 
  }

  let finalFileContent = originalMeta.fileContent || fileContent;
  if (!finalFileContent || finalFileContent === 'null') finalFileContent = '';

  let summary = extractedReason || originalMeta.summary || "No reason provided.";

  return [{ json: {
    audit_passed: auditPassed, 
    updated_state: updatedState, 
    notification_text: notificationText,
    is_proposal: isProposal, 
    hbrId: rawHbrId || '', 
    buildId: buildId,
    filePath: finalFilePath, 
    fileContent: finalFileContent,
    reason: summary
  } }];
})();

const response = $input.first().json;
let rawCode = '';
try {
  const candidates = Reflect.get(response, 'candidates');
  if (candidates && candidates.length > 0) {
    const content = Reflect.get(candidates[0], 'content');
    if (content) {
      const parts = Reflect.get(content, 'parts');
      if (parts && parts.length > 0) {
        rawCode = Reflect.get(parts[0], 'text') || '';
      }
    }
  }
} catch (e) {
  // Silent fail, rawCode defaults to ''
}
rawCode = rawCode.replace(/^\x60\x60\x60[a-z]*\n/i, '').replace(/\n\x60\x60\x60$/i, '').trim();
return [{ json: { ...$('Automated Testing Suite').first().json, fileContent: rawCode } }];

const suite = $('Automated Testing Suite').first().json;
const extract = $('Extract Code').first().json;
if (suite.filePath === 'IGNORE') return [];
const encodedContent = Buffer.from(extract.fileContent || '').toString('base64');
const commitMessage = suite.updated_state.current_phase + ' - [AUTO] FEAT(evolution): Autonomous code mutation';
return [{ json: { ...extract, encodedContent, commitMessage } }];

const suite = $('Automated Testing Suite').first().json;
const encodedContent = Buffer.from(JSON.stringify(suite.updated_state, null, 2)).toString('base64');
const commitMessage = suite.updated_state.current_phase + ' - [AUTO] CHORE(orchestration): Promote phase to prod';
return [{ json: { encodedContent, commitMessage } }];
